class EMAModel:
    """Exponential moving average of model parameters for stable evaluation."""
    def __init__(self, model, decay=0.999):
        self.decay = decay
        # Shadow copy — updated every step
        self.shadow = {name: p.data.clone() for name, p in model.named_parameters()}

    def update(self, model):
        for name, p in model.named_parameters():
            self.shadow[name] = self.decay * self.shadow[name] + (1 - self.decay) * p.data

    def apply(self, model):
        """Apply shadow weights to model (for evaluation)."""
        self._backup = {name: p.data.clone() for name, p in model.named_parameters()}
        for name, p in model.named_parameters():
            p.data.copy_(self.shadow[name])

    def restore(self, model):
        """Restore original weights after evaluation."""
        for name, p in model.named_parameters():
            p.data.copy_(self._backup[name])


# Usage:
# ema = EMAModel(G, decay=0.999)
# for each training step:
#   update G ...
#   ema.update(G)
# For evaluation:
# ema.apply(G)
# generate samples
# ema.restore(G)
